esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.watch.count IS NOT NULL
// Peak watch count per node in the time window
| STATS max_watches = MAX(metrics.zookeeper.watch.count) BY host.name
// Official docs recommend alerting above 10,000 watches
// High watch counts risk notification storms during topology changes
// Adjust based on your client workload and Kafka topology size
| WHERE max_watches > 10000
